  8ŌåÆexport interface AppContext {
  9ŌåÆ	user: Session["user"] | null;
 10ŌåÆ	session: Session["session"] | null;
 11ŌåÆ	apiKeyId: string | null;
 12ŌåÆ}
 13ŌåÆ
 14ŌåÆexport const os = implement(contract).$context<AppContext>();
 15ŌåÆ
 16ŌåÆexport const authMiddleware = os.middleware(async ({ context, next }) => {
 17ŌåÆ	if (!context.user || !context.session) {
 18ŌåÆ		throw new ORPCError("UNAUTHORIZED");
 19ŌåÆ	}
 20ŌåÆ	return next({
 21ŌåÆ		context: {
 22ŌåÆ			user: context.user,
 23ŌåÆ			session: context.session,
 24ŌåÆ			apiKeyId: context.apiKeyId,
 25ŌåÆ		},
 26ŌåÆ	});
 27ŌåÆ});
 28ŌåÆ
 29ŌåÆexport const orgMiddleware = os.middleware(async ({ context, next }) => {
 30ŌåÆ	if (!context.user || !context.session) {
 31ŌåÆ		throw new ORPCError("UNAUTHORIZED");
 32ŌåÆ	}
 33ŌåÆ	const organizationId =
 34ŌåÆ		(context.session as Record<string, unknown>).activeOrganizationId ??
 35ŌåÆ		context.user.id;
 36ŌåÆ	if (!organizationId || typeof organizationId !== "string") {
 37ŌåÆ		throw new ORPCError("BAD_REQUEST", {
 38ŌåÆ			message: "No active organization",
 39ŌåÆ		});
 40ŌåÆ	}
 41ŌåÆ
 42ŌåÆ	// Personal workspace: user is implicitly the owner
 43ŌåÆ	let userRole: "owner" | "admin" | "member" = "owner";
 44ŌåÆ
 45ŌåÆ	// When the active org is not the user's personal workspace, verify membership
 46ŌåÆ	if (organizationId !== context.user.id) {
 47ŌåÆ		const membership = await db
 48ŌåÆ			.select({ id: member.id, role: member.role })
 49ŌåÆ			.from(member)
 50ŌåÆ			.where(
 51ŌåÆ				and(
 52ŌåÆ					eq(member.organizationId, organizationId),
 53ŌåÆ					eq(member.userId, context.user.id),
 54ŌåÆ				),
 55ŌåÆ			)
 56ŌåÆ			.limit(1);
 57ŌåÆ
 58ŌåÆ		if (membership.length === 0) {
 59ŌåÆ			throw new ORPCError("FORBIDDEN", {
 60ŌåÆ				message: "Not a member of the active organization",
 61ŌåÆ			});
 62ŌåÆ		}
 63ŌåÆ		const row = membership[0];
 64ŌåÆ		if (row) {
 65ŌåÆ			userRole = (row.role as "owner" | "admin" | "member") ?? "member";
 66ŌåÆ		}
 67ŌåÆ	}
 68ŌåÆ
 69ŌåÆ	const isOrgAdmin = userRole === "owner" || userRole === "admin";
 70ŌåÆ
 71ŌåÆ	return next({
 72ŌåÆ		context: {
 73ŌåÆ			user: context.user,
 74ŌåÆ			session: context.session,
 75ŌåÆ			apiKeyId: context.apiKeyId,
 76ŌåÆ			organizationId,
 77ŌåÆ			userRole,
 78ŌåÆ			isOrgAdmin,
 79ŌåÆ		},
 80ŌåÆ	});
 81ŌåÆ});
 82ŌåÆ
 83ŌåÆexport const ingestAuthMiddleware = os.middleware(async ({ context, next }) => {
 84ŌåÆ	if (!context.user) {
 85ŌåÆ		throw new ORPCError("UNAUTHORIZED");
 86ŌåÆ	}
 87ŌåÆ
 88ŌåÆ	if (!context.session && !context.apiKeyId) {
 89ŌåÆ		throw new ORPCError("UNAUTHORIZED");
 90ŌåÆ	}
 91ŌåÆ
 92ŌåÆ	return next({
 93ŌåÆ		context: {
 94ŌåÆ			user: context.user,
 95ŌåÆ			session: context.session,
 96ŌåÆ			apiKeyId: context.apiKeyId,
 97ŌåÆ		},
 98ŌåÆ	});
 99ŌåÆ});
